142: func listenToSystemSignals(ctx context.Context, s gserver) {
143: 	signalChan := make(chan os.Signal, 1)
144: 	sighupChan := make(chan os.Signal, 1)
145: 
146: 	signal.Notify(sighupChan, syscall.SIGHUP)
147: 	signal.Notify(signalChan, os.Interrupt, syscall.SIGTERM)
148: 
