150: 		select {
151: 		case <-sighupChan:
152: 			if err := log.Reload(); err != nil {
153: 				fmt.Fprintf(os.Stderr, "Failed to reload loggers: %s\n", err)
154: 			}
155: 		case sig := <-signalChan:
156: 			ctx, cancel := context.WithTimeout(ctx, 30*time.Second)
157: 			defer cancel()
158: 			if err := s.Shutdown(ctx, fmt.Sprintf("System signal: %s", sig)); err != nil {
159: 				fmt.Fprintf(os.Stderr, "Timed out waiting for server to shut down\n")
160: 			}
161: 			return
162: 		}
163: 	}
164: }
